parameters.body:
={
  "model": "brawn-mini",
  "messages": [
    {
      "role": "system",
      "content": "You are a home lab troubleshooting assistant. Be concise and actionable."
    },
    {
      "role": "user",
      "content": "A home lab service is down. Analyze this alert and provide:\n1. What likely went wrong (1-2 sentences)\n2. The most likely fix (numbered steps, max 3)\n3. A command to check container logs if applicable\n\nAlert details:\n- Service: {{ $node['Webhook — Uptime Kuma Alert'].json.monitor.name }}\n- URL: {{ $node['Webhook — Uptime Kuma Alert'].json.monitor.url }}\n- Message: {{ $node['Webhook — Uptime Kuma Alert'].json.heartbeat.msg }}\n- Down duration: {{ $node['Webhook — Uptime Kuma Alert'].json.heartbeat.duration }} seconds"
    }
  ],
  "stream": false
}

={
  "username": "Node B Health Monitor",
  "embeds": [
    {
      "title": "🔴 Service Down: {{ $node['Webhook — Uptime Kuma Alert'].json.monitor.name }}",
      "description": "{{ $node['LiteLLM — Analyze Error'].json.choices[0].message.content }}",
      "color": 16711680,
      "fields": [
        {
          "name": "URL",
          "value": "{{ $node['Webhook — Uptime Kuma Alert'].json.monitor.url }}",
          "inline": true
        },
        {
          "name": "Down for",
          "value": "{{ Math.round($node['Webhook — Uptime Kuma Alert'].json.heartbeat.duration / 60) }} min",
          "inline": true
        }
      ],
      "footer": {
        "text": "Node B Health Monitor via n8n + LiteLLM"
      }
    }
  ]
}

={
  "model": "phi4-mini",
  "prompt": "A home lab service is down. Analyze this alert and provide:
1. What likely went wrong (1-2 sentences)
2. The most likely fix (numbered steps, max 3)
3. A command to check container logs if applicable

Alert details:
- Service: {{ $node['Webhook — Uptime Kuma Alert'].json.monitor.name }}
- URL: {{ $node['Webhook — Uptime Kuma Alert'].json.monitor.url }}
- Message: {{ $node['Webhook — Uptime Kuma Alert'].json.heartbeat.msg }}
- Down duration: {{ $node['Webhook — Uptime Kuma Alert'].json.heartbeat.duration }} seconds

Be concise and actionable.",
  "stream": false
}

={
  "username": "Node B Health Monitor",
  "embeds": [
    {
      "title": "🔴 Service Down: {{ $node['Webhook — Uptime Kuma Alert'].json.monitor.name }}",
      "description": "{{ $node['Ollama — Analyze Error'].json.response }}",
      "color": 16711680,
      "fields": [
        {
          "name": "URL",
          "value": "{{ $node['Webhook — Uptime Kuma Alert'].json.monitor.url }}",
          "inline": true
        },
        {
          "name": "Down for",
          "value": "{{ Math.round($node['Webhook — Uptime Kuma Alert'].json.heartbeat.duration / 60) }} min",
          "inline": true
        }
      ],
      "footer": {
        "text": "Node B Health Monitor via n8n + Ollama"
      }
    }
  ]
}
